+        private void TestHeartbeatMonitor()
+        {
+            OracleLog.Write("SELF_TEST", ">>> TESTING HEARTBEAT MONITOR");
+
+            var monitor = new HeartbeatMonitor(TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(15));
+            DateTime now = DateTime.UtcNow;
+
+            // Scenario 1: Unknown Engine
+            double secondsUnknown = monitor.SecondsSinceLastPulse("UnknownEngine", now);
+            OracleLog.Write("SELF_TEST", $"Scenario 1 (Unknown Engine): Expected=Infinity, Actual={secondsUnknown}");
+
+            // Scenario 2: Newly Pulsed Engine
+            monitor.Pulse("EngineA", now);
+            double secondsNew = monitor.SecondsSinceLastPulse("EngineA", now);
+            OracleLog.Write("SELF_TEST", $"Scenario 2 (New Pulse): Expected=0, Actual={secondsNew}");
+
+            // Scenario 3: Elapsed Time (10 seconds)
+            DateTime later = now.AddSeconds(10);
+            double secondsElapsed = monitor.SecondsSinceLastPulse("EngineA", later);
+            OracleLog.Write("SELF_TEST", $"Scenario 3 (Elapsed 10s): Expected=10, Actual={secondsElapsed}");
+
+            // Scenario 4: Negative Elapsed Time (Clock drift)
+            DateTime earlier = now.AddSeconds(-5);
+            double secondsNegative = monitor.SecondsSinceLastPulse("EngineA", earlier);
+            OracleLog.Write("SELF_TEST", $"Scenario 4 (Earlier Time): Expected=0, Actual={secondsNegative}");
+
+            // Scenario 5: Invalid Engine Names
+            double secondsEmpty = monitor.SecondsSinceLastPulse("", now);
+            double secondsNull = monitor.SecondsSinceLastPulse(null, now);
+            OracleLog.Write("SELF_TEST", $"Scenario 5 (Invalid Names): Empty={secondsEmpty}, Null={secondsNull}");
+
+            // Scenario 6: Mixed DateTimeKind (Local vs Utc)
+            DateTime localNow = DateTime.SpecifyKind(now, DateTimeKind.Local);
+            double secondsLocal = monitor.SecondsSinceLastPulse("EngineA", localNow);
+            // EnsureUtc converts local to universal, so it should still be consistent
+            OracleLog.Write("SELF_TEST", $"Scenario 6 (Local Time): Expected consistent, Actual={secondsLocal}");
+
+            // Scenario 7: State verification alongside seconds
+            HeartbeatState state = monitor.GetState("EngineA", later);
+            OracleLog.Write("SELF_TEST", $"Scenario 7 (State at 10s): Expected=Warning, Actual={state}");
+
+            // Scenario 8: Evaluated Snapshot
+            HeartbeatMonitorSnapshot snapshot = monitor.Evaluate(later);
+            var record = snapshot.Records[0];
+            OracleLog.Write("SELF_TEST", $"Scenario 8 (Snapshot): Engine={record.EngineName}, Seconds={record.SecondsSinceLastPulse}, State={record.State}");
+        }
